#!/usr/bin/env python3
import os, base64
path = os.path.join("lib", "constants", "colors.ts")
os.makedirs(os.path.dirname(path), exist_ok=True)
with open(path, "wb") as f:
    f.write(base64.b64decode(''))
print("Written:", path)
print("Now: git add . && git commit -m \"Fix duplicate Bar key in colors\" && vercel --prod")
